Retourne le nombre de demandes archivées. p_user_id optionnel pour l''audit.';


--
-- Name: sp_generer_bons(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sp_generer_bons(p_demande_id integer, p_genere_par integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_nombre     INT;
    v_valeur     NUMERIC(12,2);
    v_validite   INT;
    v_date_exp   TIMESTAMP;
    v_code       VARCHAR(64);
    v_count      INT := 0;
    v_ref        VARCHAR(50);
    i            INT;
BEGIN
    -- Vérifier que la demande est approuvée
    SELECT nombre_bons, valeur_unitaire, validite_jours, reference
    INTO v_nombre, v_valeur, v_validite, v_ref
    FROM demande
    WHERE demande_id = p_demande_id AND statuts = 'APPROUVE';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Demande % non trouvée ou non approuvée', p_demande_id;
    END IF;

    -- Calculer la date d'expiration
    v_date_exp := CURRENT_TIMESTAMP + (v_validite || ' days')::INTERVAL;

    -- Générer chaque bon avec un code unique
    FOR i IN 1..v_nombre LOOP
        v_code := v_ref || '-' || LPAD(i::TEXT, 4, '0') || '-' ||
                  UPPER(SUBSTRING(MD5(RANDOM()::TEXT || CLOCK_TIMESTAMP()::TEXT) FROM 1 FOR 8));

        INSERT INTO bon (demande_id, code_unique, qr_data, valeur, date_expiration)
        VALUES (p_demande_id, v_code, v_code, v_valeur, v_date_exp);

        v_count := v_count + 1;
    END LOOP;

    -- Mettre à jour le statut de la demande
    UPDATE demande
    SET statuts = 'GENERE',
        date_generation = CURRENT_TIMESTAMP,
        genere_par = p_genere_par
    WHERE demande_id = p_demande_id;

    -- Log audit
    INSERT INTO audit_log (table_name, record_id, action, nouveau_val, utilisateur_id, contexte)
    VALUES ('demande', p_demande_id, 'GENERATION',
            jsonb_build_object('bons_generes', v_count, 'valeur_unitaire', v_valeur),
            p_genere_par,
            v_count || ' bons générés pour la demande ' || v_ref);

    RETURN v_count;
END;
$$;


ALTER FUNCTION public.sp_generer_bons(p_demande_id integer, p_genere_par integer) OWNER TO postgres;

--
-- Name: sp_redimer_bon(character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sp_redimer_bon(p_code_unique character varying, p_magasin_id integer, p_utilisateur_id integer) RETURNS TABLE(succes boolean, message text, bon_valeur numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_bon_id     INT;
    v_statut     VARCHAR(20);
    v_expiration TIMESTAMP;
    v_valeur     NUMERIC(12,2);
    v_demande_id INT;
BEGIN
    -- Chercher le bon
    SELECT b.bon_id, b.statut, b.date_expiration, b.valeur, b.demande_id
    INTO v_bon_id, v_statut, v_expiration, v_valeur, v_demande_id
    FROM bon b
    WHERE b.code_unique = p_code_unique
    FOR UPDATE; -- Verrouillage pour anti double-spend

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Code invalide : bon introuvable'::TEXT, 0::NUMERIC;
        RETURN;
    END IF;

    -- Vérifier si déjà rédimé
    IF v_statut = 'REDIME' THEN
        RETURN QUERY SELECT FALSE, 'Ce bon a déjà été utilisé'::TEXT, 0::NUMERIC;
        RETURN;
    END IF;

    -- Vérifier si expiré
    IF v_expiration < CURRENT_TIMESTAMP THEN
        UPDATE bon SET statut = 'EXPIRE' WHERE bon_id = v_bon_id;
        RETURN QUERY SELECT FALSE, 'Ce bon est expiré depuis le ' || TO_CHAR(v_expiration, 'DD/MM/YYYY')::TEXT, 0::NUMERIC;
        RETURN;
    END IF;

    -- Vérifier si annulé
    IF v_statut != 'ACTIF' THEN
        RETURN QUERY SELECT FALSE, ('Ce bon est ' || v_statut)::TEXT, 0::NUMERIC;
        RETURN;
    END IF;

    -- Effectuer la rédemption
    UPDATE bon SET statut = 'REDIME' WHERE bon_id = v_bon_id;

    INSERT INTO redemption (bon_id, magasin_id, utilisateur_id)
    VALUES (v_bon_id, p_magasin_id, p_utilisateur_id);

    -- Audit
    INSERT INTO audit_log (table_name, record_id, action, nouveau_val, utilisateur_id, contexte)
    VALUES ('bon', v_bon_id, 'REDEMPTION',
            jsonb_build_object('magasin_id', p_magasin_id, 'valeur', v_valeur, 'code', p_code_unique),
            p_utilisateur_id,
            'Rédemption du bon ' || p_code_unique || ' en magasin');

    RETURN QUERY SELECT TRUE, ('Bon validé — Valeur : Rs ' || TO_CHAR(v_valeur, 'FM999,999.00'))::TEXT, v_valeur;
END;
$$;


ALTER FUNCTION public.sp_redimer_bon(p_code_unique character varying, p_magasin_id integer, p_utilisateur_id integer) OWNER TO postgres;

--
-- Name: sp_statistiques_globales(character varying, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sp_statistiques_globales(p_role character varying DEFAULT 'Administrateur'::character varying, p_user_id integer DEFAULT NULL::integer) RETURNS TABLE(total_demandes bigint, montant_total numeric, bons_actifs bigint, bons_redimes bigint, bons_expires bigint, taux_redemption numeric, demandes_attente bigint, demandes_approuvees bigint, bons_expirant_30j bigint, redemptions_today bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        COUNT(DISTINCT d.demande_id)::BIGINT                                         AS total_demandes,
        COALESCE(SUM(d.montant_total), 0)::NUMERIC                                   AS montant_total,
        COUNT(b.bon_id) FILTER (WHERE b.statut = 'ACTIF')::BIGINT                   AS bons_actifs,
        COUNT(b.bon_id) FILTER (WHERE b.statut = 'REDIME')::BIGINT                  AS bons_redimes,
        COUNT(b.bon_id) FILTER (WHERE b.statut = 'EXPIRE'
                                   OR (b.statut = 'ACTIF'
                                       AND b.date_expiration < CURRENT_TIMESTAMP))::BIGINT AS bons_expires,
        CASE
            WHEN COUNT(b.bon_id) > 0
            THEN ROUND(
                    COUNT(b.bon_id) FILTER (WHERE b.statut = 'REDIME')::NUMERIC
                    / COUNT(b.bon_id)::NUMERIC * 100, 1
                 )
            ELSE 0
        END::NUMERIC                                                                  AS taux_redemption,
        COUNT(DISTINCT d.demande_id)
            FILTER (WHERE d.statuts = 'EN_ATTENTE_PAIEMENT')::BIGINT                AS demandes_attente,
        COUNT(DISTINCT d.demande_id)
            FILTER (WHERE d.statuts = 'APPROUVE')::BIGINT                           AS demandes_approuvees,
        COUNT(b.bon_id)
            FILTER (WHERE b.statut = 'ACTIF'
                      AND b.date_expiration BETWEEN CURRENT_TIMESTAMP
                                                AND CURRENT_TIMESTAMP + INTERVAL '30 days')::BIGINT
                                                                                     AS bons_expirant_30j,
        COUNT(r.redemption_id)
            FILTER (WHERE r.date_redemption::date = CURRENT_DATE)::BIGINT           AS redemptions_today
    FROM demande d
    LEFT JOIN bon b      ON b.demande_id = d.demande_id
    LEFT JOIN redemption r ON r.bon_id   = b.bon_id
    WHERE
        -- Administrateur / Approbateur : tous les magasins
        -- Manager / Collaborateur : uniquement leur magasin si magasin_id connu
        (
            p_role IN ('Administrateur', 'Approbateur', 'Comptable')
            OR p_user_id IS NULL
            OR d.magasin_id IN (
                SELECT m.magasin_id FROM magasin m
                WHERE m.superviseur_id = p_user_id
                  OR p_role NOT IN ('Superviseur_Magasin')
            )
        );
END;
$$;


ALTER FUNCTION public.sp_statistiques_globales(p_role character varying, p_user_id integer) OWNER TO postgres;

--
-- Name: FUNCTION sp_statistiques_globales(p_role character varying, p_user_id integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.sp_statistiques_globales(p_role character varying, p_user_id integer) IS 'Retourne les KPIs du tableau de bord en un seul appel DB.
Respecte le filtrage par rôle : Administrateur voit tout, Superviseur_Magasin
voit uniquement les données de son magasin.';


--
-- Name: trg_demande_date_modification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_demande_date_modification() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_user_id_text TEXT;
    v_user_id      INT  := NULL;
    v_username     TEXT := NULL;
BEGIN
    NEW.date_modification := CURRENT_TIMESTAMP;

    -- Lire l'identifiant posé par Java (SET app.current_user_id = ?)
    v_user_id_text := current_setting('app.current_user_id', true);
    IF v_user_id_text IS NOT NULL AND v_user_id_text <> '' THEN
        BEGIN
            v_user_id := v_user_id_text::INT;
            SELECT username INTO v_username FROM utilisateur WHERE userid = v_user_id;
        EXCEPTION WHEN others THEN
            v_user_id  := NULL;
            v_username := NULL;
        END;
    END IF;

    IF OLD.statuts IS DISTINCT FROM NEW.statuts THEN
        INSERT INTO audit_log (
            table_name, record_id, action,
            ancien_val, nouveau_val,
            utilisateur_id, username, contexte
        )
        VALUES (
            'demande',
            NEW.demande_id,
            CASE NEW.statuts
                WHEN 'PAYE'     THEN 'PAIEMENT'
                WHEN 'APPROUVE' THEN 'APPROBATION'
                WHEN 'GENERE'   THEN 'GENERATION'
                WHEN 'ENVOYE'   THEN 'ENVOI'
                WHEN 'REJETE'   THEN 'REJET'
                WHEN 'ANNULE'   THEN 'ANNULATION'
                WHEN 'ARCHIVE'  THEN 'ARCHIVAGE_MASSIF'
                ELSE 'CHANGEMENT_STATUT'
            END,
            jsonb_build_object('statuts', OLD.statuts),
            jsonb_build_object('statuts', NEW.statuts, 'reference', NEW.reference),
            v_user_id,
            v_username,
            'Statut : ' || OLD.statuts || ' → ' || NEW.statuts
              || CASE WHEN NEW.reference IS NOT NULL THEN ' (' || NEW.reference || ')' ELSE '' END
        );
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_demande_date_modification() OWNER TO postgres;

--
-- Name: trg_fn_anti_double_spend(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_anti_double_spend() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_statut VARCHAR(30);
BEGIN
    SELECT statut INTO v_statut FROM bon WHERE bon_id = NEW.bon_id;

    IF v_statut = 'REDIME' THEN
        RAISE EXCEPTION
            'DOUBLE_SPEND: le bon % (id=%) est déjà rédimé — opération refusée.',
            (SELECT code_unique FROM bon WHERE bon_id = NEW.bon_id), NEW.bon_id
            USING ERRCODE = 'P0001';
    END IF;

    IF v_statut = 'EXPIRE' THEN
        RAISE EXCEPTION
            'BON_EXPIRE: le bon % (id=%) a expiré — rédemption refusée.',
            (SELECT code_unique FROM bon WHERE bon_id = NEW.bon_id), NEW.bon_id
            USING ERRCODE = 'P0002';
    END IF;

    -- Log automatique tentative de double-spend (si bon déjà REDIME atteint ce point
    -- via un autre chemin, le RAISE ci-dessus aurait arrêté — ce log est pour l'audit)
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_fn_anti_double_spend() OWNER TO postgres;

--
-- Name: trg_fn_bon_expire_auto(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_bon_expire_auto() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Si on essaie de mettre à jour un bon encore marqué ACTIF mais expiré
    IF NEW.statut = 'ACTIF' AND NEW.date_expiration < CURRENT_TIMESTAMP THEN
        NEW.statut := 'EXPIRE';
        -- Pas d'exception : juste normalisation silencieuse
    END IF;

    -- Empêcher de "réactiver" un bon déjà REDIME ou ANNULE
    IF OLD.statut IN ('REDIME', 'ANNULE') AND NEW.statut NOT IN ('REDIME', 'ANNULE') THEN
        RAISE EXCEPTION
            'BON_IMMUABLE: le bon % (id=%) est déjà % et ne peut plus être modifié.',
            OLD.code_unique, OLD.bon_id, OLD.statut
            USING ERRCODE = 'P0020';
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_fn_bon_expire_auto() OWNER TO postgres;

--
-- Name: FUNCTION trg_fn_bon_expire_auto(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.trg_fn_bon_expire_auto() IS 'Trigger BEFORE UPDATE(statut) sur bon.
1) Normalise ACTIF→EXPIRE si date_expiration dépassée.
2) Bloque toute tentative de "dé-rédimer" un bon déjà REDIME ou ANNULE.';


--
-- Name: trg_fn_client_actif_check(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_client_actif_check() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_actif  BOOLEAN;
    v_nom    VARCHAR(150);
BEGIN
    SELECT actif, name
    INTO v_actif, v_nom
    FROM client
    WHERE clientid = NEW.clientid;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'CLIENT_INTROUVABLE: aucun client avec clientid=%', NEW.clientid
            USING ERRCODE = 'P0010';
    END IF;

    IF NOT v_actif THEN
        RAISE EXCEPTION 'CLIENT_INACTIF: le client "%" (id=%) est désactivé — demande refusée.',
            v_nom, NEW.clientid
            USING ERRCODE = 'P0011';
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_fn_client_actif_check() OWNER TO postgres;

--
-- Name: FUNCTION trg_fn_client_actif_check(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.trg_fn_client_actif_check() IS 'Trigger BEFORE INSERT sur demande. Rejette toute demande liée à un client inactif.
Sécurité DB-level complémentaire au contrôle Java.';


--
-- Name: trg_fn_demande_montant_coherence(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_demande_montant_coherence() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Validation métier : valeurs positives
    -- Complète les CHECK constraints (chk_nombre_bons, chk_valeur_unitaire)
    -- pour un message d'erreur plus explicite côté application.
    IF NEW.nombre_bons <= 0 THEN
        RAISE EXCEPTION 'MONTANT_INVALIDE: nombre_bons doit être > 0 (reçu: %)', NEW.nombre_bons
            USING ERRCODE = 'P0003';
    END IF;

    IF NEW.valeur_unitaire <= 0 THEN
        RAISE EXCEPTION 'MONTANT_INVALIDE: valeur_unitaire doit être > 0 (reçu: %)', NEW.valeur_unitaire
            USING ERRCODE = 'P0004';
    END IF;

    -- montant_total est défini GENERATED ALWAYS AS (nombre_bons * valeur_unitaire) STORED
    -- dans le CREATE TABLE : PostgreSQL le recalcule automatiquement, aucune action requise ici.
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trg_fn_demande_montant_coherence() OWNER TO postgres;

--
-- Name: trg_fn_normalize_email(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_fn_normalize_email() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.email IS NOT NULL THEN
        NEW.email := LOWER(TRIM(NEW.email));
    END IF;
    RETURN NEW;
END;
$$;


