--
-- Name: trg_redemption_marquer_redime(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_redemption_marquer_redime() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE bon SET statut = 'REDIME'
    WHERE bon_id = NEW.bon_id AND statut != 'REDIME';
    RETURN NEW;
END;
$$;


