-- Name: audit_log; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.audit_log (
    audit_id integer NOT NULL,
    table_name character varying(50) NOT NULL,
    record_id integer NOT NULL,
    action character varying(20) NOT NULL,
    ancien_val jsonb,
    nouveau_val jsonb,
    utilisateur_id integer,
    username character varying(80),
    ip_address character varying(45),
    contexte text,
    date_action timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT chk_action CHECK (((action)::text = ANY ((ARRAY['CREATION'::character varying, 'MODIFICATION'::character varying, 'SUPPRESSION'::character varying, 'PAIEMENT'::character varying, 'APPROBATION'::character varying, 'GENERATION'::character varying, 'ENVOI'::character varying, 'ENVOI_ECHEC'::character varying, 'RENVOI_EMAIL'::character varying, 'REDEMPTION'::character varying, 'REDEMPTION_ECHOUEE'::character varying, 'UTILISATION_BON'::character varying, 'REJET'::character varying, 'ANNULATION'::character varying, 'ARCHIVAGE'::character varying, 'ARCHIVAGE_MASSIF'::character varying, 'CHANGEMENT_STATUT'::character varying, 'CONNEXION'::character varying, 'CONNEXION_ECHOUEE'::character varying, 'CONNEXION_BLOQUEE'::character varying, 'DECONNEXION'::character varying, 'INSCRIPTION'::character varying, 'COMPTE_VERROUILLE'::character varying, 'DEVERROUILLAGE'::character varying, 'CHANGE_PASSWORD'::character varying, 'UPDATE_PROFILE'::character varying, 'UPDATE_ROLE'::character varying, 'DELETE'::character varying, 'UPDATE_EMAIL'::character varying, 'RESET_PASSWORD'::character varying, 'RESET_PASSWORD_DEMANDE'::character varying, 'RESET_PASSWORD_OK'::character varying, 'RESET_PASSWORD_SUCCES'::character varying, 'RESET_PASSWORD_ECHEC'::character varying])::text[])))
);


