    clientid integer NOT NULL,
    magasin_id integer,
    nombre_bons integer DEFAULT 1 NOT NULL,
    valeur_unitaire numeric(12,2) DEFAULT 0 NOT NULL,
    montant_total numeric(14,2) GENERATED ALWAYS AS (((nombre_bons)::numeric * valeur_unitaire)) STORED,
    type_bon character varying(30) DEFAULT 'Standard'::character varying,
    validite_jours integer DEFAULT 365,
    motif text,
    description text,
    email character varying(150),
    email_destinataire character varying(150),
    statuts character varying(30) DEFAULT 'EN_ATTENTE_PAIEMENT'::character varying NOT NULL,
    cree_par integer,
    date_creation timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    date_demande timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    paiement_valide boolean DEFAULT false,
    date_paiement timestamp without time zone,
    valide_par integer,
    approuve boolean DEFAULT false,
    approuve_par integer,
    date_approbation timestamp without time zone,
    date_generation timestamp without time zone,
    genere_par integer,
    date_modification timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT chk_nombre_bons CHECK ((nombre_bons > 0)),
    CONSTRAINT chk_statuts CHECK (((statuts)::text = ANY ((ARRAY['EN_ATTENTE_PAIEMENT'::character varying, 'PAYE'::character varying, 'APPROUVE'::character varying, 'GENERE'::character varying, 'ENVOYE'::character varying, 'REJETE'::character varying, 'ANNULE'::character varying, 'ARCHIVE'::character varying])::text[]))),
    CONSTRAINT chk_valeur_unitaire CHECK ((valeur_unitaire >= (0)::numeric))
);


