--
-- Name: v_activite_magasin_jour; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_activite_magasin_jour AS
 SELECT m.magasin_id,
    m.nom_magasin,
    count(r.redemption_id) AS nb_redemptions_jour,
    COALESCE(sum(b.valeur), (0)::numeric) AS montant_redeme_jour,
    max(r.date_redemption) AS derniere_redemption,
    min(r.date_redemption) AS premiere_redemption
   FROM ((public.magasin m
     LEFT JOIN public.redemption r ON (((r.magasin_id = m.magasin_id) AND ((r.date_redemption)::date = CURRENT_DATE))))
     LEFT JOIN public.bon b ON ((b.bon_id = r.bon_id)))
  WHERE (m.actif = true)
  GROUP BY m.magasin_id, m.nom_magasin
  ORDER BY (count(r.redemption_id)) DESC;


ALTER VIEW public.v_activite_magasin_jour OWNER TO postgres;

--
-- Name: VIEW v_activite_magasin_jour; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.v_activite_magasin_jour IS 'Synthèse des rédemptions du jour par magasin. Rafraîchie en temps réel.
Utilisée par le dashboard POS et le reporting siège.';


--
-- Name: v_bons_details; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_bons_details AS
 SELECT b.bon_id,
    b.code_unique,
    b.valeur,
    b.statut,
    b.date_emission,
    b.date_expiration,
        CASE
            WHEN ((b.statut)::text = 'REDIME'::text) THEN 'Utilisé'::text
            WHEN ((b.statut)::text = 'ANNULE'::text) THEN 'Annulé'::text
            WHEN (b.date_expiration < CURRENT_TIMESTAMP) THEN 'Expiré'::text
            WHEN (b.date_expiration < (CURRENT_TIMESTAMP + '30 days'::interval)) THEN 'Proche expiration'::text
            ELSE 'Actif'::text
        END AS statut_detaille,
    d.reference AS demande_reference,
    d.invoice_reference,
    c.name AS client_nom,
    c.email AS client_email,
    m.nom_magasin AS magasin_emission,
    r.date_redemption,
    mr.nom_magasin AS magasin_redemption,
    ur.username AS redime_par
   FROM ((((((public.bon b
     JOIN public.demande d ON ((b.demande_id = d.demande_id)))
     LEFT JOIN public.client c ON ((d.clientid = c.clientid)))
     LEFT JOIN public.magasin m ON ((d.magasin_id = m.magasin_id)))
     LEFT JOIN public.redemption r ON ((b.bon_id = r.bon_id)))
     LEFT JOIN public.magasin mr ON ((r.magasin_id = mr.magasin_id)))
     LEFT JOIN public.utilisateur ur ON ((r.utilisateur_id = ur.userid)));


ALTER VIEW public.v_bons_details OWNER TO postgres;

--
-- Name: v_bons_proche_expiration; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_bons_proche_expiration AS
 SELECT bon_id,
    code_unique,
    valeur,
    statut,
    date_emission,
    date_expiration,
    statut_detaille,
    demande_reference,
    invoice_reference,
    client_nom,
    client_email,
    magasin_emission,
    date_redemption,
    magasin_redemption,
    redime_par
   FROM public.v_bons_details
  WHERE (((statut)::text = 'ACTIF'::text) AND (date_expiration > CURRENT_TIMESTAMP) AND (date_expiration < (CURRENT_TIMESTAMP + ((COALESCE(( SELECT (app_settings.setting_value)::integer AS setting_value
           FROM public.app_settings
          WHERE ((app_settings.setting_key)::text = 'bon_expiration_seuil_jours'::text)), 30) || ' days'::text))::interval)));


ALTER VIEW public.v_bons_proche_expiration OWNER TO postgres;

--
-- Name: v_demandes_completes; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_demandes_completes AS
 SELECT d.demande_id,
    d.reference,
    d.invoice_reference,
    c.name AS client_nom,
    c.email AS client_email,
    c.company AS client_societe,
    d.nombre_bons,
    d.valeur_unitaire,
    d.montant_total,
    d.type_bon,
    d.validite_jours,
    d.statuts,
    m.nom_magasin,
    s.nom AS societe_nom,
    d.date_creation,
    d.date_demande,
    d.date_paiement,
    d.date_approbation,
    d.date_generation,
    u_cree.username AS cree_par_nom,
    u_valid.username AS valide_par_nom,
    u_appro.username AS approuve_par_nom
   FROM ((((((public.demande d
     LEFT JOIN public.client c ON ((d.clientid = c.clientid)))
     LEFT JOIN public.magasin m ON ((d.magasin_id = m.magasin_id)))
     LEFT JOIN public.societe s ON ((m.societe_id = s.societe_id)))
     LEFT JOIN public.utilisateur u_cree ON ((d.cree_par = u_cree.userid)))
     LEFT JOIN public.utilisateur u_valid ON ((d.valide_par = u_valid.userid)))
     LEFT JOIN public.utilisateur u_appro ON ((d.approuve_par = u_appro.userid)));


ALTER VIEW public.v_demandes_completes OWNER TO postgres;

