    statuts,
    nom_magasin,
    societe_nom,
    date_creation,
    date_demande,
    date_paiement,
    date_approbation,
    date_generation,
    cree_par_nom,
    valide_par_nom,
    approuve_par_nom
   FROM public.v_demandes_completes
  WHERE ((statuts)::text = 'EN_ATTENTE_PAIEMENT'::text);


ALTER VIEW public.v_demandes_attente_paiement OWNER TO postgres;

--
-- Name: v_rapport_odbc; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_rapport_odbc AS
 SELECT d.demande_id,
    d.reference AS demande_reference,
    d.invoice_reference AS facture_reference,
    d.statuts AS demande_statut,
    d.nombre_bons,
    d.valeur_unitaire,
    d.montant_total,
    d.type_bon,
    d.validite_jours,
    d.date_creation AS demande_date_creation,
    d.date_paiement,
    d.date_approbation,
    d.date_generation,
    c.clientid,
    c.name AS client_nom,
    c.email AS client_email,
    c.contact_number AS client_telephone,
    c.company AS client_societe,
    b.bon_id,
    b.code_unique,
    b.valeur AS bon_valeur,
    b.statut AS bon_statut,
    b.date_emission,
    b.date_expiration,
        CASE
            WHEN ((b.statut)::text = 'REDIME'::text) THEN 'Utilisé'::text
            WHEN ((b.statut)::text = 'ANNULE'::text) THEN 'Annulé'::text
            WHEN (b.date_expiration < CURRENT_TIMESTAMP) THEN 'Expiré'::text
            WHEN (b.date_expiration < (CURRENT_TIMESTAMP + '30 days'::interval)) THEN 'Proche expiration'::text
            ELSE 'Actif'::text
        END AS bon_statut_lisible,
    (GREATEST((0)::numeric, EXTRACT(day FROM ((b.date_expiration)::timestamp with time zone - CURRENT_TIMESTAMP))))::integer AS jours_restants,
    r.redemption_id,
    r.date_redemption,
    mr.nom_magasin AS magasin_redemption,
    ur.username AS caissier_redemption,
    m.nom_magasin AS magasin_emission,
    s.nom AS societe,
    u_cree.username AS cree_par,
    u_appro.username AS approuve_par
   FROM (((((((((public.demande d
     LEFT JOIN public.client c ON ((c.clientid = d.clientid)))
     LEFT JOIN public.magasin m ON ((m.magasin_id = d.magasin_id)))
     LEFT JOIN public.societe s ON ((s.societe_id = m.societe_id)))
     LEFT JOIN public.bon b ON ((b.demande_id = d.demande_id)))
     LEFT JOIN public.redemption r ON ((r.bon_id = b.bon_id)))
     LEFT JOIN public.magasin mr ON ((mr.magasin_id = r.magasin_id)))
     LEFT JOIN public.utilisateur ur ON ((ur.userid = r.utilisateur_id)))
     LEFT JOIN public.utilisateur u_cree ON ((u_cree.userid = d.cree_par)))
     LEFT JOIN public.utilisateur u_appro ON ((u_appro.userid = d.approuve_par)));


ALTER VIEW public.v_rapport_odbc OWNER TO postgres;

--
-- Name: VIEW v_rapport_odbc; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.v_rapport_odbc IS 'Vue plate dénormalisée pour connexion ODBC (Excel / Power BI / LibreOffice Calc).
Contient toutes les colonnes utiles. Chaque ligne = 1 bon avec sa demande parente.
Connexion : DSN PostgreSQL → Tableau croisé dynamique sur montant_total / statut.';


--
-- Name: v_stats_societe; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_stats_societe AS
 SELECT s.nom AS societe,
    count(DISTINCT d.demande_id) AS total_demandes,
    COALESCE(sum(d.montant_total), (0)::numeric) AS montant_total,
    count(DISTINCT b.bon_id) FILTER (WHERE ((b.statut)::text = 'ACTIF'::text)) AS bons_actifs,
    count(DISTINCT b.bon_id) FILTER (WHERE ((b.statut)::text = 'REDIME'::text)) AS bons_redimes,
    count(DISTINCT b.bon_id) FILTER (WHERE (((b.statut)::text = 'EXPIRE'::text) OR (b.date_expiration < CURRENT_TIMESTAMP))) AS bons_expires
   FROM (((public.societe s
     LEFT JOIN public.magasin m ON ((s.societe_id = m.societe_id)))
     LEFT JOIN public.demande d ON ((m.magasin_id = d.magasin_id)))
     LEFT JOIN public.bon b ON ((d.demande_id = b.demande_id)))
  GROUP BY s.societe_id, s.nom;


ALTER VIEW public.v_stats_societe OWNER TO postgres;

--
-- Name: v_tableau_bord_temps_reel; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_tableau_bord_temps_reel AS
 SELECT count(DISTINCT d.demande_id) AS total_demandes,
    count(DISTINCT d.demande_id) FILTER (WHERE ((d.statuts)::text = 'EN_ATTENTE_PAIEMENT'::text)) AS demandes_attente_paiement,
    count(DISTINCT d.demande_id) FILTER (WHERE ((d.statuts)::text = 'APPROUVE'::text)) AS demandes_approuvees,
    count(DISTINCT d.demande_id) FILTER (WHERE ((d.statuts)::text = 'ARCHIVE'::text)) AS demandes_archivees,
    COALESCE(sum(d.montant_total), (0)::numeric) AS montant_total,
    count(b.bon_id) AS total_bons,
    count(b.bon_id) FILTER (WHERE ((b.statut)::text = 'ACTIF'::text)) AS bons_actifs,
    count(b.bon_id) FILTER (WHERE ((b.statut)::text = 'REDIME'::text)) AS bons_redimes,
    count(b.bon_id) FILTER (WHERE (((b.statut)::text = 'EXPIRE'::text) OR (((b.statut)::text = 'ACTIF'::text) AND (b.date_expiration < CURRENT_TIMESTAMP)))) AS bons_expires,
    count(b.bon_id) FILTER (WHERE (((b.statut)::text = 'ACTIF'::text) AND ((b.date_expiration >= CURRENT_TIMESTAMP) AND (b.date_expiration <= (CURRENT_TIMESTAMP + '30 days'::interval))))) AS bons_expirant_30j,
        CASE
            WHEN (count(b.bon_id) > 0) THEN round((((count(b.bon_id) FILTER (WHERE ((b.statut)::text = 'REDIME'::text)))::numeric / (count(b.bon_id))::numeric) * (100)::numeric), 1)
            ELSE (0)::numeric
        END AS taux_redemption_pct,
    count(r.redemption_id) FILTER (WHERE ((r.date_redemption)::date = CURRENT_DATE)) AS redemptions_aujourd_hui,
    COALESCE(sum(b2.valeur) FILTER (WHERE ((r2.date_redemption)::date = CURRENT_DATE)), (0)::numeric) AS montant_redeme_aujourd_hui
   FROM ((((public.demande d
     LEFT JOIN public.bon b ON ((b.demande_id = d.demande_id)))
     LEFT JOIN public.redemption r ON ((r.bon_id = b.bon_id)))
     LEFT JOIN public.bon b2 ON ((b2.bon_id = r.bon_id)))
     LEFT JOIN public.redemption r2 ON ((r2.bon_id = b2.bon_id)));


ALTER VIEW public.v_tableau_bord_temps_reel OWNER TO postgres;

--
-- Name: VIEW v_tableau_bord_temps_reel; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.v_tableau_bord_temps_reel IS 'Vue temps réel pour le dashboard siège — tous les KPIs en un seul SELECT.
